<?php namespace App\Policies; use App\Models\User; use App\Models\CaseModel; use Illuminate\Auth\Access\HandlesAuthorization; class CasePolicy { use HandlesAuthorization; public function view(User $user, CaseModel $case) { return $user->id === $case->user_id || $user->is_admin; } public function create(User $user) { return true; } public function update(User $user, CaseModel $case) { return $user->id === $case->user_id || $user->is_admin; } public function delete(User $user, CaseModel $case) { return $user->id === $case->user_id || $user->is_admin; } }